const getProjectConflictTimestampMs = (project) => {
  const updatedAtMs = toTimestampMs(project?.updatedAt);
  if (updatedAtMs > 0) return updatedAtMs;
  const changeFeed = normalizeProjectActivityFeed(project?.changeFeed, project);
  return changeFeed.reduce((latestMs, entry) => {
    const entryMs = toTimestampMs(entry?.createdAt);
    return entryMs > latestMs ? entryMs : latestMs;
  }, 0);
};
const mergeProjectChangeFeedForConflict = (baseProject, incomingProject) => {
  const baseFeed = normalizeProjectActivityFeed(baseProject?.changeFeed, baseProject);
  const incomingFeed = normalizeProjectActivityFeed(incomingProject?.changeFeed, incomingProject);
  const mergedById = new Map();
  [...incomingFeed, ...baseFeed].forEach((entry) => {
    const entryId = String(entry?.id || '').trim();
    if (!entryId || mergedById.has(entryId)) return;
    mergedById.set(entryId, entry);
  });
  return Array.from(mergedById.values())
    .sort((left, right) => {
      const timeDiff = new Date(right.createdAt).getTime() - new Date(left.createdAt).getTime();
      if (timeDiff !== 0) return timeDiff;
      return String(left.id || '').localeCompare(String(right.id || ''), undefined, {
        sensitivity: 'base',
      });
    })
    .slice(0, MAX_PROJECT_ACTIVITY_FEED);
};
const mergeAccountProjectsForConflict = (baseProjectsInput, incomingProjectsInput) => {
  const baseProjects = Array.isArray(baseProjectsInput) ? baseProjectsInput : [];
  const incomingProjects = Array.isArray(incomingProjectsInput) ? incomingProjectsInput : [];
  const projectOrder = [];
  const baseById = new Map();
  const incomingById = new Map();

  baseProjects.forEach((project, index) => {
    const projectId = String(project?.id || '').trim();
    if (!projectId) {
      projectOrder.push(`base:${index}`);
      baseById.set(`base:${index}`, project);
      return;
    }
    if (!projectOrder.includes(projectId)) {
      projectOrder.push(projectId);
    }
    baseById.set(projectId, project);
  });
  incomingProjects.forEach((project, index) => {
    const projectId = String(project?.id || '').trim();
    if (!projectId) {
      projectOrder.push(`incoming:${index}`);
      incomingById.set(`incoming:${index}`, project);
      return;
    }
    if (!projectOrder.includes(projectId)) {
      projectOrder.push(projectId);
    }
    incomingById.set(projectId, project);
  });

  return projectOrder
    .map((projectId) => {
      const baseProject = baseById.get(projectId);
      const incomingProject = incomingById.get(projectId);
      if (!baseProject) return incomingProject;
      if (!incomingProject) return baseProject;

      const baseMs = getProjectConflictTimestampMs(baseProject);
      const incomingMs = getProjectConflictTimestampMs(incomingProject);
      const preferredProject = incomingMs >= baseMs ? incomingProject : baseProject;
      const secondaryProject = preferredProject === incomingProject ? baseProject : incomingProject;
      const mergedNotes = mergeProjectNotesContentByRevision(
        baseProject?.notesContent,
        baseProject?.noteRevisionMap,
        incomingProject?.notesContent,
        incomingProject?.noteRevisionMap
      );
      const mergedNotesPresence = mergeProjectNotesPresence(
        baseProject?.notesPresence,
        incomingProject?.notesPresence
      );
      const mergedChangeFeed = mergeProjectChangeFeedForConflict(baseProject, incomingProject);
      const mergedMembers = Array.from(
        new Set(
          [...(Array.isArray(baseProject?.members) ? baseProject.members : []), ...(Array.isArray(incomingProject?.members) ? incomingProject.members : [])]
            .map((member) => String(member || '').trim().toLowerCase())
            .filter(Boolean)
        )
      );
      const teamMemberMap = new Map();
      [...(Array.isArray(baseProject?.teamMembers) ? baseProject.teamMembers : []), ...(Array.isArray(incomingProject?.teamMembers) ? incomingProject.teamMembers : [])].forEach(
        (memberInput) => {
          const member = memberInput && typeof memberInput === 'object' ? memberInput : null;
          if (!member) return;
          const key = String(member.userId || member.id || member.username || member.name || '')
            .trim()
            .toLowerCase();
          if (!key) return;
          const existingMember = teamMemberMap.get(key);
          teamMemberMap.set(key, existingMember ? { ...existingMember, ...member } : member);
        }
      );
      const mergedTeamMembers = Array.from(teamMemberMap.values());
      const mergedRoles = Array.from(
        new Set(
          [...(Array.isArray(baseProject?.roles) ? baseProject.roles : []), ...(Array.isArray(incomingProject?.roles) ? incomingProject.roles : [])]
            .map((role) => String(role || '').trim())
            .filter(Boolean)
        )
      );
      const mergedPositions = Array.from(
        new Set(
          [...(Array.isArray(baseProject?.positions) ? baseProject.positions : []), ...(Array.isArray(incomingProject?.positions) ? incomingProject.positions : [])]
            .map((position) => String(position || '').trim())
            .filter(Boolean)
        )
      );
      const mergedDepartments = Array.from(
        new Set(
          [...(Array.isArray(baseProject?.departments) ? baseProject.departments : []), ...(Array.isArray(incomingProject?.departments) ? incomingProject.departments : [])]
            .map((department) => String(department || '').trim())
            .filter(Boolean)
        )
      );
      const mergedDepartmentColors = {
        ...(baseProject?.departmentColors && typeof baseProject.departmentColors === 'object'
          ? baseProject.departmentColors
          : {}),
        ...(incomingProject?.departmentColors && typeof incomingProject.departmentColors === 'object'
          ? incomingProject.departmentColors
          : {}),
      };
      const preferredNotesPreferences =
        incomingProject?.notesPreferences &&
        typeof incomingProject.notesPreferences === 'object' &&
        !Array.isArray(incomingProject.notesPreferences)
          ? incomingProject.notesPreferences
          : baseProject?.notesPreferences;
      const preferredVisibility =
        typeof incomingProject?.isVisible === 'boolean'
          ? incomingProject.isVisible
          : baseProject?.isVisible;

      return {
        ...secondaryProject,
        ...preferredProject,
        notesContent: mergedNotes.notesContent,
        noteRevisionMap: mergedNotes.noteRevisionMap,
        notesPresence: mergedNotesPresence,
        changeFeed: mergedChangeFeed,
        members: mergedMembers,
        teamMembers: mergedTeamMembers,
        roles: mergedRoles,
        positions: mergedPositions,
        departments: mergedDepartments,
        departmentColors: mergedDepartmentColors,
        notesPreferences: preferredNotesPreferences || {},
        isVisible: typeof preferredVisibility === 'boolean' ? preferredVisibility : Boolean(preferredProject?.isVisible),
        projectResourceRows: normalizeProjectResourceRows(
          preferredProject?.projectResourceRows ?? secondaryProject?.projectResourceRows
        ),
      };
    })
    .filter(Boolean);
};
const getEventConflictTimestampMs = (event) => {
  const updatedAtMs = toTimestampMs(event?.updatedAt);
  if (updatedAtMs > 0) return updatedAtMs;
  return toTimestampMs(event?.createdAt);
};
const mergeAccountEventsForConflict = (baseEventsInput, incomingEventsInput) => {
  const baseEvents = Array.isArray(baseEventsInput) ? baseEventsInput : [];
  const incomingEvents = Array.isArray(incomingEventsInput) ? incomingEventsInput : [];
  const mergedByKey = new Map();
  [...baseEvents, ...incomingEvents].forEach((eventInput) => {
    const event = eventInput && typeof eventInput === 'object' ? eventInput : null;
    if (!event) return;
    const eventId = String(event.id || '').trim();
    const fallbackKey = `f:${event?.projectId || ''}|${event?.title || ''}|${event?.startDate || ''}|${event?.endDate || ''}|${event?.startTime || ''}|${event?.endTime || ''}`;
    const key = eventId ? `id:${eventId}` : fallbackKey;
    const existing = mergedByKey.get(key);
    if (!existing) {
      mergedByKey.set(key, event);
      return;
    }
    const existingMs = getEventConflictTimestampMs(existing);
    const incomingMs = getEventConflictTimestampMs(event);
    if (incomingMs >= existingMs) {
      mergedByKey.set(key, event);
    }
  });
  return Array.from(mergedByKey.values());
};
const mergeSeenProjectUpdateIdsForConflict = (baseIdsInput, incomingIdsInput) => {
  const ids = Array.from(
    new Set(
      [...(Array.isArray(baseIdsInput) ? baseIdsInput : []), ...(Array.isArray(incomingIdsInput) ? incomingIdsInput : [])]
        .map((id) => String(id || '').trim())
        .filter(Boolean)
    )
  );
  return ids.slice(-1400);
};
const mergeAccountDbPayloadForConflict = (basePayloadInput, incomingPayloadInput) => {
  const basePayload =
    basePayloadInput && typeof basePayloadInput === 'object' && !Array.isArray(basePayloadInput)
      ? basePayloadInput
      : {};
  const incomingPayload =
    incomingPayloadInput && typeof incomingPayloadInput === 'object' && !Array.isArray(incomingPayloadInput)
      ? incomingPayloadInput
      : {};

  const mergedPayload = {
    ...basePayload,
    ...incomingPayload,
    projects: mergeAccountProjectsForConflict(basePayload.projects, incomingPayload.projects),
    events: mergeAccountEventsForConflict(basePayload.events, incomingPayload.events),
    ideasWorkspaceData: mergeIdeasWorkspaceData(
      basePayload.ideasWorkspaceData,
      incomingPayload.ideasWorkspaceData
    ),
    projectTodosByProjectId: mergeProjectTodosByProjectId(
      basePayload.projectTodosByProjectId,
      incomingPayload.projectTodosByProjectId
    ),
    seenProjectUpdateIds: mergeSeenProjectUpdateIdsForConflict(
      basePayload.seenProjectUpdateIds,
      incomingPayload.seenProjectUpdateIds
    ),
  };
  return mergedPayload;
};
const getAccountSaveQueueState = (userId) => {
  const state = ACCOUNT_DB_SAVE_QUEUE_BY_USER.get(userId);
  if (state) return state;
  const nextState = {
    inFlight: false,
    jobs: [],
  };
  ACCOUNT_DB_SAVE_QUEUE_BY_USER.set(userId, nextState);
  return nextState;
};
const hasPendingAccountSaveQueue = (userId) => {
  const state = ACCOUNT_DB_SAVE_QUEUE_BY_USER.get(userId);
  if (!state) return false;
  return state.inFlight || state.jobs.length > 0;
};
const flushAccountSaveQueue = async (userId) => {
  const state = ACCOUNT_DB_SAVE_QUEUE_BY_USER.get(userId);
  if (!state || state.inFlight) return;
  state.inFlight = true;
  while (state.jobs.length > 0) {
    const nextJob = state.jobs.shift();
    if (!nextJob) continue;
    let payloadToSave =
      nextJob.payload && typeof nextJob.payload === 'object' && !Array.isArray(nextJob.payload)
        ? nextJob.payload
        : {};
    try {
      let didSave = false;
      for (let attempt = 0; attempt < 4; attempt += 1) {
        const baseVersion = ACCOUNT_DB_VERSION_BY_USER.get(userId);
        try {
          const result = await requestCloudDataApi(`/data/account/${encodeURIComponent(userId)}`, {
            method: 'PUT',
            body: {
              payload: payloadToSave,
              baseVersion: Number.isInteger(baseVersion) ? baseVersion : undefined,
            },
          });
          const savedVersion = toSafeAccountVersion(result?.version);
          if (savedVersion !== null) {
            ACCOUNT_DB_VERSION_BY_USER.set(userId, savedVersion);
          }
          writeAccountDbPayload(userId, payloadToSave);
          didSave = true;
          break;
        } catch (error) {
          const isConflict = Number(error?.status || 0) === 409;
          const remotePayload =
            isConflict &&
            error?.payload?.payload &&
            typeof error.payload.payload === 'object' &&
            !Array.isArray(error.payload.payload)
              ? error.payload.payload
              : null;
          const remoteVersion = toSafeAccountVersion(error?.payload?.version);
          if (remoteVersion !== null) {
            ACCOUNT_DB_VERSION_BY_USER.set(userId, remoteVersion);
          }
          if (isConflict && remotePayload) {
            payloadToSave = mergeAccountDbPayloadForConflict(remotePayload, payloadToSave);
            writeAccountDbPayload(userId, payloadToSave);
            continue;
          }
          if (Number(error?.status || 0) === 401 || Number(error?.status || 0) === 403) {
            console.warn('Failed to save account data to Cloud API: unauthorized request.');
            break;
          }
          console.warn('Failed to save account data to Firestore API:', error.message);
          break;
        }
      }
      if (!didSave) {
        writeAccountDbPayload(userId, payloadToSave);
      }
    } catch (error) {
      console.warn('Failed to save account data to Firestore API:', error.message);
    } finally {
      nextJob.resolves.forEach((resolve) => resolve());
    }
  }
  state.inFlight = false;
  if (state.jobs.length === 0) {
    ACCOUNT_DB_SAVE_QUEUE_BY_USER.delete(userId);
  }
};
const enqueueAccountPayloadSave = (userId, payload) =>
  new Promise((resolve) => {
    const state = getAccountSaveQueueState(userId);
    if (state.jobs.length > 0) {
      const lastJob = state.jobs[state.jobs.length - 1];
      lastJob.payload = payload;
      lastJob.resolves.push(resolve);
    } else {
      state.jobs.push({
        payload,
        resolves: [resolve],
      });
    }
    if (!state.inFlight) {
      void flushAccountSaveQueue(userId);
    }
  });

const normalizeProjectInvite = (invite) => {
  const status = VALID_PROJECT_INVITE_STATUSES.has(invite?.status)
    ? invite.status
    : PROJECT_INVITE_STATUSES.PENDING;

  return {
    id: String(invite?.id || generateId()),
    projectId: String(invite?.projectId || '').trim(),
    projectName: String(invite?.projectName || '').trim(),
    ownerId: String(invite?.ownerId || '').trim(),
    ownerUsername: String(invite?.ownerUsername || '').trim().toLowerCase(),
    invitedUserId: String(invite?.invitedUserId || '').trim() || null,
    invitedUsername: String(invite?.invitedUsername || '').trim().toLowerCase(),
    invitedEmail: String(invite?.invitedEmail || '').trim().toLowerCase(),
    status,
    createdAt: String(invite?.createdAt || STABLE_FALLBACK_ISO),
    respondedAt: invite?.respondedAt ? String(invite.respondedAt) : null,
  };
};

const getProjectInvites = () => {
  try {
    const rawData = localStorage.getItem(PROJECT_INVITES_KEY);
    if (!rawData) return [];

    const parsed = JSON.parse(rawData);
    if (!Array.isArray(parsed)) return [];

    return parsed
      .map(normalizeProjectInvite)
      .filter(
        (invite) =>
          invite.projectId &&
          invite.ownerId &&
          (invite.invitedUserId || invite.invitedUsername || invite.invitedEmail)
      );
  } catch {
    return [];
  }
};

const saveProjectInvites = (invites) => {
  const normalized = (Array.isArray(invites) ? invites : []).map(normalizeProjectInvite);
  localStorage.setItem(PROJECT_INVITES_KEY, JSON.stringify(normalized));
};

const isInviteForUser = (invite, user) => {
  const userId = String(user?.id || '').trim();
  const username = String(user?.username || '').trim().toLowerCase();
  const email = String(user?.email || '').trim().toLowerCase();
  if (!invite || !user) return false;

  if (invite.invitedUserId && userId && invite.invitedUserId === userId) return true;
  if (invite.invitedUsername && username && invite.invitedUsername === username) return true;
  if (invite.invitedEmail && email && invite.invitedEmail === email) return true;
  return false;
};

const isProjectAccessibleByUser = (project, user) => {
  if (!project || !user) return false;

  const userId = String(user?.id || '').trim();
  const username = String(user?.username || '').trim().toLowerCase();
  const email = String(user?.email || '').trim().toLowerCase();

  const ownerId = String(project?.ownerId || '').trim();
  const ownerUsername = String(project?.ownerUsername || '').trim().toLowerCase();
  if ((userId && ownerId === userId) || (username && ownerUsername === username)) {
    return true;
  }

  const projectMembers = Array.isArray(project?.members)
    ? project.members.map((member) => String(member || '').trim().toLowerCase())
    : [];
  if ((username && projectMembers.includes(username)) || (email && projectMembers.includes(email))) {
    return true;
  }

  const teamMembers = Array.isArray(project?.teamMembers) ? project.teamMembers : [];
  return teamMembers.some((member) => {
    const memberId = String(member?.id || member?.userId || '').trim();
    const memberUsername = String(member?.username || member?.name || '').trim().toLowerCase();
    const memberEmail = String(member?.email || '').trim().toLowerCase();
    return (
      (userId && memberId === userId) ||
      (username && memberUsername === username) ||
      (email && memberEmail === email)
    );
  });
};

const stripLocalOnlyProjectFields = (project) => {
  if (!project || typeof project !== 'object') return {};
  const nextProject = { ...project };
  delete nextProject.isVisible;
  // Keep note target selection local per user, but keep shared note content.
  delete nextProject.notesPreferences;
  return nextProject;
};

const cloneLocalNotesPreferences = (value) => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
  return { ...value };
};

const resolveAccountScopedNotesPreferences = (
  preferencesInput,
  { currentUserId = '', projectOwnerId = '' } = {}
) => {
  const preferences = cloneLocalNotesPreferences(preferencesInput);
  const normalizedCurrentUserId = String(currentUserId || '').trim();
  const normalizedProjectOwnerId = String(projectOwnerId || '').trim();
  const preferenceUserId = String(preferences.userId || '').trim();

  if (preferenceUserId) {
    if (normalizedCurrentUserId && preferenceUserId === normalizedCurrentUserId) {
      return preferences;
    }
    return {};
  }

  // Legacy preferences without userId:
  // keep only for owner account, clear for shared member accounts.
  if (
    normalizedCurrentUserId &&
    normalizedProjectOwnerId &&
    normalizedProjectOwnerId !== normalizedCurrentUserId
  ) {
    return {};
  }

  return preferences;
};

const normalizeLastVisitedView = (value) => {
  if (!value || typeof value !== 'object') {
    return { ...DEFAULT_LAST_VISITED_VIEW };
  }

  const profileOpen = Boolean(value.profileOpen);
  const type =
    value.type === STARTUP_VIEW_MODES.PROJECT
      ? STARTUP_VIEW_MODES.PROJECT
      : STARTUP_VIEW_MODES.CALENDAR;
  const projectId = type === STARTUP_VIEW_MODES.PROJECT ? String(value.projectId || '').trim() || null : null;
  const projectTab =
    type === STARTUP_VIEW_MODES.PROJECT
      ? normalizeProjectDashboardTab(value.projectTab)
      : DEFAULT_PROJECT_DASHBOARD_TAB;
  const projectManagerOpen =
    type === STARTUP_VIEW_MODES.CALENDAR && !profileOpen ? Boolean(value.projectManagerOpen) : false;

  if (profileOpen) {
    return {
      type: STARTUP_VIEW_MODES.CALENDAR,
      projectId: null,
      projectTab: DEFAULT_PROJECT_DASHBOARD_TAB,
      profileOpen: true,
      projectManagerOpen: false,
    };
  }

  return {
    type,
    projectId,
    projectTab,
    profileOpen: false,
    projectManagerOpen,
  };
};

const isJsonEqual = (left, right) => {
  try {
    return JSON.stringify(left) === JSON.stringify(right);
  } catch {
    return false;
  }
};

const buildProjectComparableSnapshot = (projectsInput, { ignoreNotesRealtimeFields = false } = {}) =>
  (Array.isArray(projectsInput) ? projectsInput : []).map((projectInput) => {
    const project =
      projectInput && typeof projectInput === 'object' && !Array.isArray(projectInput)
        ? projectInput
        : {};
    if (!ignoreNotesRealtimeFields) return project;
    return {
      ...project,
      // Ignore high-churn notes fields to prevent non-notes tabs from re-render flicker.
      notesContent: null,
      noteRevisionMap: null,
      notesPresence: null,
    };
  });

const postAuthApi = async (path, payload) => {
  if (!AUTH_API_BASE_URL) {
    throw new Error('Auth API is not configured. Set VITE_AUTH_API_BASE_URL or AUTH_API_BASE_URL.');
  }

  const response = await fetch(`${AUTH_API_BASE_URL}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });

  let result = null;
  try {
    result = await response.json();
  } catch {
    result = null;
  }

  if (!response.ok) {
    const message = result?.message || 'Authentication request failed.';
    const error = new Error(message);
    error.status = response.status;
    error.payload = result;
    throw error;
  }

  return result;
};

const requestCloudDataApi = async (path, options = {}) => {
  if (!AUTH_API_BASE_URL) {
    throw new Error('Auth API is not configured. Set VITE_AUTH_API_BASE_URL or AUTH_API_BASE_URL.');
  }

  const method = String(options.method || 'GET').toUpperCase();
  const authToken = getStoredAuthToken();
  const headers = {
    'Content-Type': 'application/json',
  };
  if (authToken) {
    headers.Authorization = `Bearer ${authToken}`;
  }
  const response = await fetch(`${AUTH_API_BASE_URL}${path}`, {
    method,
    headers,
    body: options.body ? JSON.stringify(options.body) : undefined,
    cache: 'no-store',
  });

  let result = null;
  try {
    result = await response.json();
  } catch {
    result = null;
  }

  if (!response.ok) {
    const message = result?.message || 'Cloud data request failed.';
    const error = new Error(message);
    error.status = response.status;
    error.payload = result;
    throw error;
  }

  return result;
};

const normalizeGoogleCalendarSelection = (selectedCalendarIds) =>
  Array.from(
    new Set(
      (Array.isArray(selectedCalendarIds) ? selectedCalendarIds : [])
        .map((calendarId) => String(calendarId || '').trim())
        .filter(Boolean)
    )
  );
const GOOGLE_CALENDAR_WRITABLE_ROLES = new Set(['owner', 'writer']);
const canWriteGoogleCalendar = (calendar) =>
  GOOGLE_CALENDAR_WRITABLE_ROLES.has(String(calendar?.accessRole || '').trim().toLowerCase());

const normalizeGoogleCalendarCalendars = (calendarsInput) =>
  (Array.isArray(calendarsInput) ? calendarsInput : [])
    .map((calendar) => {
      const id = String(calendar?.id || '').trim();
      if (!id) return null;
      return {
        id,
        summary: String(calendar?.summary || id).trim() || id,
        primary: calendar?.primary === true,
        accessRole: String(calendar?.accessRole || '').trim(),
        backgroundColor: String(calendar?.backgroundColor || '').trim(),
      };
    })
    .filter(Boolean);

const normalizeGoogleCalendarStatus = (status) => ({
  ...DEFAULT_GOOGLE_CALENDAR_STATUS,
  ...(status && typeof status === 'object' ? status : {}),
  linked: Boolean(status?.linked),
  linkedEmail: String(status?.linkedEmail || '').trim().toLowerCase(),
  selectedCalendarIds: normalizeGoogleCalendarSelection(status?.selectedCalendarIds),
  configured: Boolean(status?.configured),
  redirectUri: String(status?.redirectUri || '').trim(),
});
const PROJECT_BOARD_ITEM_TYPES = new Set(['todo', 'note']);
const toProjectBoardItemTimestampMs = (item) => {
  const updatedAtMs = toTimestampMs(item?.updatedAt);
  if (updatedAtMs > 0) return updatedAtMs;
  return toTimestampMs(item?.createdAt);
};
const normalizeProjectTodoItem = (todo) => {
  const id = String(todo?.id || generateId()).trim();
  const text = String(todo?.text || '').trim();
  if (!id || !text) return null;

  const createdAtRaw = String(todo?.createdAt || '').trim();
  const createdAt =
    createdAtRaw && !Number.isNaN(new Date(createdAtRaw).getTime())
      ? createdAtRaw
      : STABLE_FALLBACK_ISO;
  const updatedAtRaw = String(todo?.updatedAt || '').trim();
  const updatedAt =
    updatedAtRaw && !Number.isNaN(new Date(updatedAtRaw).getTime()) ? updatedAtRaw : createdAt;
  const itemTypeRaw = String(todo?.itemType || todo?.type || 'todo')
    .trim()
    .toLowerCase();
  const itemType = PROJECT_BOARD_ITEM_TYPES.has(itemTypeRaw) ? itemTypeRaw : 'todo';

  return {
    id,
    text,
    createdAt,
    updatedAt,
    itemType,
    checked: itemType === 'todo' ? Boolean(todo?.checked) : false,
  };
};
const normalizeProjectTodosByProjectId = (projectTodosInput) => {
  if (
    !projectTodosInput ||
    typeof projectTodosInput !== 'object' ||
    Array.isArray(projectTodosInput)
  ) {
    return {};
  }

  const normalized = {};

  Object.entries(projectTodosInput)
    .sort(([leftId], [rightId]) =>
      String(leftId || '').localeCompare(String(rightId || ''), undefined, { sensitivity: 'base' })
    )
    .forEach(([projectIdInput, todosInput]) => {
    const projectId = String(projectIdInput || '').trim();
    if (!projectId) return;

    const todoMap = new Map();
    (Array.isArray(todosInput) ? todosInput : []).forEach((todoInput) => {
      const todo = normalizeProjectTodoItem(todoInput);
      if (!todo || todoMap.has(todo.id)) return;
      todoMap.set(todo.id, todo);
    });

    const todos = Array.from(todoMap.values()).sort(
      (left, right) =>
        toProjectBoardItemTimestampMs(right) - toProjectBoardItemTimestampMs(left)
    );
    if (todos.length > 0) {
      normalized[projectId] = todos;
    }
    });

  return normalized;
};
const mergeProjectTodosByProjectId = (baseTodosInput, incomingTodosInput) => {
  const baseTodos = normalizeProjectTodosByProjectId(baseTodosInput);
  const incomingTodos = normalizeProjectTodosByProjectId(incomingTodosInput);
  const projectIds = Array.from(
    new Set([...Object.keys(baseTodos), ...Object.keys(incomingTodos)])
  );
  const merged = {};

  projectIds.forEach((projectId) => {
    const todoMap = new Map();
    [...(baseTodos[projectId] || []), ...(incomingTodos[projectId] || [])].forEach((todo) => {
      if (!todo?.id) return;
      const existingTodo = todoMap.get(todo.id);
      if (!existingTodo) {
        todoMap.set(todo.id, todo);
        return;
      }
      const existingMs = toProjectBoardItemTimestampMs(existingTodo);
      const incomingMs = toProjectBoardItemTimestampMs(todo);
      if (incomingMs >= existingMs) {
        todoMap.set(todo.id, todo);
      }
    });
    const todos = Array.from(todoMap.values()).sort(
      (left, right) =>
        toProjectBoardItemTimestampMs(right) - toProjectBoardItemTimestampMs(left)
    );
    if (todos.length > 0) {
      merged[projectId] = todos;
    }
  });

  return merged;
};

const loadAccountDbPayload = async (userId, options = {}) => {
  const normalizedUserId = String(userId || '').trim();
  if (!normalizedUserId) return {};
  const localPayload = readAccountDbPayload(normalizedUserId);
  const shouldAllowStaleLocalWhilePendingSave =
    options && typeof options === 'object'
      ? options.allowStaleWhilePendingQueue !== false
      : true;

  if (!AUTH_API_BASE_URL) {
    return localPayload;
  }

  try {
    if (shouldAllowStaleLocalWhilePendingSave && hasPendingAccountSaveQueue(normalizedUserId)) {
      return localPayload;
    }
    const result = await requestCloudDataApi(`/data/account/${encodeURIComponent(normalizedUserId)}`);
    const remoteVersion = toSafeAccountVersion(result?.version);
    if (remoteVersion !== null) {
      ACCOUNT_DB_VERSION_BY_USER.set(normalizedUserId, remoteVersion);
    }
    const remotePayload =
      result?.payload && typeof result.payload === 'object' && !Array.isArray(result.payload)
        ? result.payload
        : {};
    const hasRemoteData = Object.keys(remotePayload).length > 0;
    const hasLocalData = Object.keys(localPayload).length > 0;

    if (!hasRemoteData && hasLocalData) {
      await saveAccountDbPayload(normalizedUserId, localPayload);
      return localPayload;
    }

    if (!shouldAllowStaleLocalWhilePendingSave && hasPendingAccountSaveQueue(normalizedUserId)) {
      // Keep unsynced local cache intact while callers explicitly request fresh remote data for merge logic.
      return remotePayload;
    }
    writeAccountDbPayload(normalizedUserId, remotePayload);
    return remotePayload;
  } catch (error) {
    if (Number(error?.status || 0) === 401 || Number(error?.status || 0) === 403) {
      console.warn('Cloud account data request is unauthorized. Falling back to local cache.');
      return localPayload;
    }
    console.warn('Failed to load account data from Firestore API, using local cache:', error.message);
    return localPayload;
  }
};

const saveAccountDbPayload = async (userId, payload) => {
  const normalizedUserId = String(userId || '').trim();
  if (!normalizedUserId) return;

  const safePayload = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : {};
  writeAccountDbPayload(normalizedUserId, safePayload);

  if (!AUTH_API_BASE_URL) return;
  await enqueueAccountPayloadSave(normalizedUserId, safePayload);
};

const loadProjectInvitesStore = async () => {
  const localInvites = getProjectInvites();
  if (!AUTH_API_BASE_URL) {
    return localInvites;
  }

  try {
    const result = await requestCloudDataApi('/data/project-invites');
    const remoteInvites = Array.isArray(result?.invites) ? result.invites.map(normalizeProjectInvite) : [];
    if (remoteInvites.length === 0 && localInvites.length > 0) {
      await saveProjectInvitesStore(localInvites);
      return localInvites;
    }

    saveProjectInvites(remoteInvites);
    return remoteInvites;
  } catch (error) {
    console.warn('Failed to load project invites from Firestore API, using local cache:', error.message);
    return localInvites;
  }
};

const saveProjectInvitesStore = async (invitesInput) => {
  const normalizedInvites = (Array.isArray(invitesInput) ? invitesInput : []).map(normalizeProjectInvite);
  saveProjectInvites(normalizedInvites);

  if (!AUTH_API_BASE_URL) {
    return normalizedInvites;
  }

  try {
    await requestCloudDataApi('/data/project-invites', {
      method: 'PUT',
      body: { invites: normalizedInvites },
    });
  } catch (error) {
    console.warn('Failed to save project invites to Firestore API:', error.message);
  }

  return normalizedInvites;
};

const findUserByIdentifier = async (identifier) => {
  const normalizedIdentifier = String(identifier || '').trim().toLowerCase();
  if (!normalizedIdentifier) return null;

  if (AUTH_API_BASE_URL) {
    try {
      const result = await requestCloudDataApi(
        `/users/lookup?identifier=${encodeURIComponent(normalizedIdentifier)}`
      );
      return normalizeAuthUser(result?.user);
    } catch {
      return null;
    }
  }

  const users = getLocalUsers();
  const matchedUser = users.find(
    (user) => user.email === normalizedIdentifier || user.username === normalizedIdentifier
  );
  return matchedUser ? normalizeAuthUser(matchedUser) : null;
};

const PopupContext = React.createContext(null);

const toPopupOptions = (messageOrOptions, options = {}) => {
  if (typeof messageOrOptions === 'object' && messageOrOptions !== null) {
    return messageOrOptions;
  }

  return {
    ...options,
    message: String(messageOrOptions || ''),
  };
};

function PopupProvider({ children }) {
  const [popupState, setPopupState] = useState(null);
  const [promptValue, setPromptValue] = useState('');
  const [promptFormValues, setPromptFormValues] = useState({});
  const resolverRef = useRef(null);

  const closePopup = (result) => {
    const resolve = resolverRef.current;
    resolverRef.current = null;
    setPopupState(null);
    setPromptValue('');
    setPromptFormValues({});
    if (resolve) resolve(result);
  };

  const openPopup = (nextState, fallbackResult) =>
    new Promise((resolve) => {
      if (resolverRef.current) {
        resolverRef.current(fallbackResult);
      }
      resolverRef.current = resolve;
      setPopupState(nextState);
      setPromptValue(String(nextState?.defaultValue || ''));
      if (nextState?.type === 'prompt_form') {
        const initialFormValues = {};
        const fields = Array.isArray(nextState?.fields) ? nextState.fields : [];
        fields.forEach((field, index) => {
          const fieldId = String(field?.id || `field_${index + 1}`).trim();
          if (!fieldId) return;
          initialFormValues[fieldId] = String(field?.defaultValue || '');
        });
        setPromptFormValues(initialFormValues);
      } else {
        setPromptFormValues({});
      }
    });

  const showAlert = (messageOrOptions, options = {}) => {
    const config = toPopupOptions(messageOrOptions, options);
    return openPopup(
      {
        type: 'alert',
        title: config.title || 'Notice',
        message: config.message || '',
        confirmText: config.confirmText || 'OK',
        tone: config.tone || 'info',
      },
      true
    );
  };

  const showConfirm = (messageOrOptions, options = {}) => {
    const config = toPopupOptions(messageOrOptions, options);
    return openPopup(
      {
        type: 'confirm',
        title: config.title || 'Please confirm',
        message: config.message || '',
        confirmText: config.confirmText || 'Confirm',
        cancelText: config.cancelText || 'Cancel',
        tone: config.tone || 'info',
      },
      false
    );
  };

  const showPrompt = (messageOrOptions, options = {}) => {
    const config = toPopupOptions(messageOrOptions, options);
    return openPopup(
      {
        type: 'prompt',
        title: config.title || 'Enter value',
        message: config.message || '',
        confirmText: config.confirmText || 'Save',
        cancelText: config.cancelText || 'Cancel',
        placeholder: config.placeholder || '',
        defaultValue: config.defaultValue || '',
        tone: config.tone || 'info',
      },
      null
    );
  };

  const showPromptForm = (messageOrOptions, options = {}) => {
    const config = toPopupOptions(messageOrOptions, options);
    const fields = Array.isArray(config.fields) ? config.fields : [];
    const normalizedFields = fields
      .map((field, index) => {
        const fieldId = String(field?.id || `field_${index + 1}`).trim();
        if (!fieldId) return null;
        return {
          id: fieldId,
          label: String(field?.label || fieldId).trim(),
          placeholder: String(field?.placeholder || '').trim(),
          defaultValue: String(field?.defaultValue || ''),
          type: String(field?.type || 'text').trim() || 'text',
          layout: String(field?.layout || 'full').trim() || 'full',
          options: Array.isArray(field?.options)
            ? field.options
                .map((option) => {
                  if (
                    option &&
                    typeof option === 'object' &&
                    !Array.isArray(option)
                  ) {
                    const value = String(option.value ?? '').trim();
                    const label = String(option.label ?? option.value ?? '').trim();
                    if (!value || !label) return null;
                    return { value, label };
                  }
                  const value = String(option ?? '').trim();
                  if (!value) return null;
                  return { value, label: value };
                })
                .filter(Boolean)
            : [],
        };
      })
      .filter(Boolean);
    if (normalizedFields.length === 0) return Promise.resolve(null);
    return openPopup(
      {
        type: 'prompt_form',
        title: config.title || 'Enter values',
        message: config.message || '',
        confirmText: config.confirmText || 'Save',
        cancelText: config.cancelText || 'Cancel',
        tone: config.tone || 'info',
        fields: normalizedFields,
      },
      null
    );
  };

  const value = useMemo(
    () => ({
      alert: showAlert,
      confirm: showConfirm,
      prompt: showPrompt,
      promptForm: showPromptForm,
    }),
    []
  );

  const isDanger = popupState?.tone === 'danger';
  const confirmButtonClass = isDanger
    ? 'bg-red-600 hover:bg-red-700 text-white'
    : 'bg-blue-600 hover:bg-blue-700 text-white';

  return (
    <PopupContext.Provider value={value}>
      {children}
      {popupState && (
        <div className="fixed inset-0 z-[120] bg-slate-900/45 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="w-full max-w-md rounded-2xl border border-slate-200 bg-white shadow-2xl overflow-hidden">
            <div className="px-5 py-4 border-b border-slate-200 bg-slate-50">
              <h3 className="text-base font-semibold text-slate-800">{popupState.title}</h3>
            </div>
            <div className="px-5 py-4 space-y-3">
              {popupState.message && <p className="text-sm text-slate-600 whitespace-pre-wrap">{popupState.message}</p>}
              {popupState.type === 'prompt' && (
                <input
                  type="text"
                  value={promptValue}
                  onChange={(e) => setPromptValue(e.target.value)}
                  placeholder={popupState.placeholder}
                  autoFocus
                  className="w-full rounded-lg border border-slate-300 px-3 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      closePopup(promptValue);
                    }
                  }}
                />
              )}
              {popupState.type === 'prompt_form' && (
                <div className="grid grid-cols-2 gap-3">
                  {(Array.isArray(popupState.fields) ? popupState.fields : []).map((field, fieldIndex) => (
                    <label
                      key={field.id}
                      className={`block space-y-1.5 ${field.layout === 'half' ? 'col-span-1' : 'col-span-2'}`}
                    >
                      <span className="text-xs font-medium text-slate-600">{field.label}</span>
                      {field.type === 'button_group' ? (
                        <div className="flex items-center gap-2">
                          {(Array.isArray(field.options) ? field.options : []).map((option) => {
                            const optionValue = String(option?.value || '');
                            const isSelected =
                              String(promptFormValues[field.id] || '') === optionValue;
                            return (
                              <button
                                key={`${field.id}-${optionValue}`}
                                type="button"
                                onClick={() =>
                                  setPromptFormValues((prev) => ({
                                    ...prev,
                                    [field.id]: optionValue,
                                  }))
                                }
                                className={`inline-flex h-9 min-w-[40px] items-center justify-center rounded-lg border px-3 text-sm font-semibold transition-colors ${
                                  isSelected
                                    ? 'border-blue-600 bg-blue-600 text-white'
                                    : 'border-slate-300 bg-white text-slate-700 hover:bg-slate-100'
                                }`}
                              >
                                {option?.label || optionValue}
                              </button>
                            );
                          })}
                        </div>
                      ) : (
                        <input
                          type={field.type || 'text'}
                          value={String(promptFormValues[field.id] || '')}
                          onChange={(e) =>
                            setPromptFormValues((prev) => ({
                              ...prev,
                              [field.id]: e.target.value,
                            }))
                          }
                          placeholder={field.placeholder || ''}
                          autoFocus={fieldIndex === 0}
                          className="w-full rounded-lg border border-slate-300 px-3 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        />
                      )}
                    </label>
                  ))}
                </div>
              )}
            </div>
            <div className="px-5 py-4 border-t border-slate-200 bg-slate-50 flex items-center justify-end gap-2">
              {popupState.type !== 'alert' && (
                <button
                  type="button"
                  onClick={() => closePopup(popupState.type === 'confirm' ? false : null)}
                  className="px-4 py-2 rounded-lg border border-slate-300 bg-white text-slate-700 hover:bg-slate-100 transition-colors text-sm font-medium"
                >
                  {popupState.cancelText || 'Cancel'}
                </button>
              )}
              <button
                type="button"
                onClick={() =>
                  closePopup(
                    popupState.type === 'confirm'
                      ? true
                      : popupState.type === 'prompt'
                      ? promptValue
                      : popupState.type === 'prompt_form'
                      ? promptFormValues
                      : true
                  )
                }
                className={`px-4 py-2 rounded-lg transition-colors text-sm font-medium ${confirmButtonClass}`}
              >
                {popupState.confirmText || 'OK'}
              </button>
            </div>
          </div>
        </div>
      )}
    </PopupContext.Provider>
  );
}

function usePopup() {
  const context = React.useContext(PopupContext);
  if (!context) {
    throw new Error('usePopup must be used inside PopupProvider.');
  }
  return context;
}

const migrateProjectUsername = (project, oldUsername, newUsername) => {
  const normalizedOld = String(oldUsername || '').trim().toLowerCase();
  const normalizedNew = String(newUsername || '').trim().toLowerCase();
  if (!normalizedOld || !normalizedNew || normalizedOld === normalizedNew) return project;

  const ownerUsername =
    String(project.ownerUsername || '').trim().toLowerCase() === normalizedOld
      ? normalizedNew
      : String(project.ownerUsername || '').trim().toLowerCase();

  const members = Array.isArray(project.members)
    ? Array.from(
        new Set(
          project.members
            .map((member) => String(member || '').trim().toLowerCase())
            .map((member) => (member === normalizedOld ? normalizedNew : member))
            .filter(Boolean)
        )
      )
    : [ownerUsername];

  const teamMembers = Array.isArray(project.teamMembers)
    ? project.teamMembers.map((member) => {
        const memberUsername = String(member?.username || member?.name || '')
          .trim()
          .toLowerCase();
        if (memberUsername !== normalizedOld) return member;

        const displayName = String(member?.name || '').trim().toLowerCase() === normalizedOld
          ? normalizedNew
          : member?.name;

        return {
          ...member,
          username: normalizedNew,
          name: displayName || normalizedNew,
        };
      })
    : project.teamMembers;

  return {
    ...project,
    ownerUsername,
    members,
    teamMembers,
  };
};

const ensureProjectOwnership = (project, owner) => {
  const members = Array.isArray(project.members) ? project.members.filter(Boolean) : [];
  const ownerUsername = project.ownerUsername || owner.username;
  const mergedMembers = members.includes(ownerUsername) ? members : [ownerUsername, ...members];
  const joinCodeSecret = ensureProjectJoinCodeSecret(project);
  const changeFeed = normalizeProjectActivityFeed(project.changeFeed, project);
  const projectResourceRows = normalizeProjectResourceRows(project.projectResourceRows);

  return {
    ...project,
    ownerId: project.ownerId || owner.id,
    ownerUsername,
    members: Array.from(new Set(mergedMembers)),
    joinCodeSecret,
    changeFeed,
    projectResourceRows,
  };
};
const inferProjectOwnerReference = (
  project,
  fallbackOwner = null,
  ownerIdByUsernameInput = null
) => {
  const ownerIdRaw = String(project?.ownerId || '').trim();
  const ownerUsernameRaw = String(project?.ownerUsername || '').trim().toLowerCase();
  const fallbackOwnerId = String(fallbackOwner?.id || '').trim();
  const fallbackOwnerUsername = String(
    fallbackOwner?.username || fallbackOwner?.name || ''
  )
    .trim()
    .toLowerCase();
  let ownerId = ownerIdRaw;
  if (!ownerId && ownerUsernameRaw && ownerIdByUsernameInput instanceof Map) {
    ownerId = String(ownerIdByUsernameInput.get(ownerUsernameRaw) || '').trim();
  }
  if (!ownerId && (!ownerUsernameRaw || ownerUsernameRaw === fallbackOwnerUsername)) {
    ownerId = fallbackOwnerId;
  }
  return {
    id: ownerId,
    username: ownerUsernameRaw || fallbackOwnerUsername,
  };
};
const ensureProjectOwnershipForAccount = (
  project,
  fallbackOwner = null,
  ownerIdByUsernameInput = null
) =>
  ensureProjectOwnership(
    project,
    inferProjectOwnerReference(project, fallbackOwner, ownerIdByUsernameInput)
  );
const getProjectSyncTimestampMs = (project) => {
  if (!project || typeof project !== 'object' || Array.isArray(project)) return 0;
  const updatedAtMs = toTimestampMs(project.updatedAt);
  if (updatedAtMs > 0) return updatedAtMs;
  const feed = normalizeProjectActivityFeed(project.changeFeed, project);
  const feedLatestMs = feed.reduce((latestMs, entry) => {
    const entryMs = toTimestampMs(entry?.createdAt);
    return entryMs > latestMs ? entryMs : latestMs;
  }, 0);
  return feedLatestMs;
};
const selectPreferredProjectSnapshot = (remoteProject, localProject) => {
  if (!remoteProject && !localProject) return null;
  if (!remoteProject) return localProject;
  if (!localProject) return remoteProject;
  const remoteMs = getProjectSyncTimestampMs(remoteProject);
  const localMs = getProjectSyncTimestampMs(localProject);
  if (localMs > remoteMs) return localProject;
  if (remoteMs > localMs) return remoteProject;
  // Tie-breaker prefers local state to avoid snapping back while save is in-flight.
  return localProject;
};

const MEMBER_COLORS = [
  'bg-blue-600',
  'bg-purple-500',
  'bg-orange-500',
  'bg-green-500',
  'bg-pink-500',
  'bg-teal-500',
  'bg-indigo-500',
];

const normalizeRoles = (roles) =>
  Array.from(
    new Set(
      (Array.isArray(roles) ? roles : [])
        .map((role) => String(role || '').trim())
        .filter(Boolean)
    )
  );

const normalizeDepartments = (departments) =>
  Array.from(
    new Set(
      (Array.isArray(departments) ? departments : [])
        .map((department) => String(department || '').trim())
        .filter(Boolean)
    )
  );
const normalizeDepartmentColorHex = (value) => {
  const color = String(value || '').trim().toLowerCase();
  return /^#[0-9a-f]{6}$/.test(color) ? color : '';
};
const pickDepartmentPresetColor = (departmentName = '') => {
  const presets = DEPARTMENT_COLOR_PRESETS.length > 0 ? DEPARTMENT_COLOR_PRESETS : ['#3b82f6'];
  const text = String(departmentName || '').trim().toLowerCase();
  const hash = Array.from(text).reduce((acc, char) => acc + char.charCodeAt(0), 0);
  return presets[Math.abs(hash) % presets.length];
};
const normalizeDepartmentColorMap = (colorMapInput, departmentsInput = []) => {
  const baseMap =
    colorMapInput && typeof colorMapInput === 'object' && !Array.isArray(colorMapInput)
      ? colorMapInput
      : {};
  const normalized = {};
  Object.entries(baseMap).forEach(([departmentName, colorValue]) => {
    const normalizedDepartmentName = String(departmentName || '').trim();
    const normalizedColorValue = normalizeDepartmentColorHex(colorValue);
    if (!normalizedDepartmentName || !normalizedColorValue) return;
    if (normalizedDepartmentName.toLowerCase() === 'unassigned') return;
    normalized[normalizedDepartmentName] = normalizedColorValue;
  });

  normalizeDepartments(departmentsInput).forEach((departmentName) => {
    if (departmentName.toLowerCase() === 'unassigned') return;
    if (!normalized[departmentName]) {
      normalized[departmentName] = pickDepartmentPresetColor(departmentName);
    }
  });

  return normalized;
};
const resolveDepartmentColorHex = (
  departmentColorMapInput,
  departmentNameInput,
  fallbackColor = '#94a3b8'
) => {
  const departmentName = String(departmentNameInput || '').trim();
  const normalizedFallback = normalizeDepartmentColorHex(fallbackColor) || '#94a3b8';
  if (!departmentName || departmentName.toLowerCase() === 'unassigned') return normalizedFallback;
  const normalizedMap = normalizeDepartmentColorMap(departmentColorMapInput, [departmentName]);
  return normalizeDepartmentColorHex(normalizedMap[departmentName]) || normalizedFallback;
};
const toRgb = (hexColorInput) => {
  const hexColor = normalizeDepartmentColorHex(hexColorInput);
  if (!hexColor) return null;
  return {
    r: Number.parseInt(hexColor.slice(1, 3), 16),
    g: Number.parseInt(hexColor.slice(3, 5), 16),
    b: Number.parseInt(hexColor.slice(5, 7), 16),
  };
};
const toRgba = (hexColorInput, alpha = 1) => {
  const rgb = toRgb(hexColorInput);
  if (!rgb) return `rgba(148, 163, 184, ${alpha})`;
  const clampedAlpha = Math.max(0, Math.min(1, Number(alpha)));
  return `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${clampedAlpha})`;
};

const getInitials = (value) => {
  const text = String(value || '').trim();
  if (!text) return '?';

  const words = text.split(/\s+/).filter(Boolean);
  if (words.length >= 2) {
    return `${words[0][0]}${words[1][0]}`.toUpperCase();
  }

  return text.slice(0, 2).toUpperCase();
};

const getRoleLevel = (role, isOwner = false) => {
  if (isOwner) return 1;

  const normalizedRole = String(role || '').toLowerCase();
  if (
    normalizedRole.includes('owner') ||
    normalizedRole.includes('approver') ||
    normalizedRole.includes('manager') ||
    normalizedRole.includes('lead')
  ) {
    return 2;
  }

  return 3;
};

const buildLocalUserLookup = () => {
  const byUsername = new Map();
  const byEmail = new Map();
  const byId = new Map();

  getLocalUsers().forEach((user) => {
    const normalizedUser = normalizeAuthUser(user);
    if (!normalizedUser) return;

    const userId = String(normalizedUser.id || '').trim();
    const username = String(normalizedUser.username || '').trim().toLowerCase();
    const email = String(normalizedUser.email || '').trim().toLowerCase();
    const avatarUrl = String(normalizedUser.avatarUrl || '').trim();
    const profile = { id: userId || null, username, email, avatarUrl };

    if (profile.id) byId.set(profile.id, profile);
    if (profile.username && !byUsername.has(profile.username)) {
      byUsername.set(profile.username, profile);
    }
    if (profile.email && !byEmail.has(profile.email)) {
      byEmail.set(profile.email, profile);
    }
  });

  return { byUsername, byEmail, byId };
};

const resolveMemberProfile = (lookup, username, existingMember = null) => {
  if (!lookup) return null;

  const normalizedUsername = String(username || existingMember?.username || existingMember?.name || '')
    .trim()
    .toLowerCase();
  const memberId = String(existingMember?.userId || '').trim();
  const memberEmail = String(existingMember?.email || '').trim().toLowerCase();

  if (normalizedUsername && lookup.byUsername.has(normalizedUsername)) {
    return lookup.byUsername.get(normalizedUsername);
  }

  if (memberId && lookup.byId.has(memberId)) {
    return lookup.byId.get(memberId);
  }

  if (memberEmail && lookup.byEmail.has(memberEmail)) {
    return lookup.byEmail.get(memberEmail);
  }

  return null;
};

const buildMemberFromUsername = (username, index, ownerUsername, existingMember = null, profileUser = null) => {
  const profileUsername = String(profileUser?.username || '').trim().toLowerCase();
  const normalizedUsername = String(username || profileUsername || existingMember?.username || existingMember?.name || '')
    .trim()
    .toLowerCase();
  const safeUsername = normalizedUsername || profileUsername || `member-${index + 1}`;
  const displayName =
    String(profileUser?.username || existingMember?.name || safeUsername).trim() || safeUsername;
  const isOwner = safeUsername === ownerUsername;
  const position = String(existingMember?.position || existingMember?.role || (isOwner ? 'Project Owner' : '')).trim();
  const department = String(existingMember?.department || 'Unassigned').trim() || 'Unassigned';
  const reportsToId = existingMember?.reportsToId || null;
  const avatarUrl = String(profileUser?.avatarUrl || existingMember?.avatarUrl || '').trim();
  const email = String(profileUser?.email || existingMember?.email || '').trim().toLowerCase();
  const userId = String(profileUser?.id || existingMember?.userId || '').trim() || null;

  return {
    id: existingMember?.id || `member-${safeUsername.replace(/\s+/g, '-')}`,
    userId,
    username: safeUsername,
    name: displayName,
    email,
    avatarUrl,
    position,
    role: position, // Backward compatibility for old UI paths
    department,
    reportsToId,
    initials: getInitials(displayName),
    color: existingMember?.color || MEMBER_COLORS[index % MEMBER_COLORS.length],
    level: existingMember?.level || getRoleLevel(position, isOwner),
  };
};

const normalizeProjectTeamMembers = (project) => {
  const ownerUsername = String(project.ownerUsername || '').trim().toLowerCase();
  const storedMembers = Array.isArray(project.teamMembers) ? project.teamMembers : [];
  const projectMembers = Array.isArray(project.members) ? project.members : [];
  const userLookup = buildLocalUserLookup();

  const allUsernames = Array.from(
    new Set(
      [ownerUsername, ...projectMembers, ...storedMembers.map((member) => member.username || member.name)]
        .map((value) => String(value || '').trim().toLowerCase())
        .filter(Boolean)
    )
  );

  const membersByUsername = new Map();
  storedMembers.forEach((member) => {
    const key = String(member?.username || member?.name || '').trim().toLowerCase();
    if (!key || membersByUsername.has(key)) return;
    membersByUsername.set(key, member);
  });

  return allUsernames.map((username, index) => {
    const existingMember = membersByUsername.get(username);
    const profileUser = resolveMemberProfile(userLookup, username, existingMember);
    return buildMemberFromUsername(username, index, ownerUsername, existingMember, profileUser);
  });
};

const addProjectMemberRecord = (project, memberUser) => {
  const ownerUsername = String(project?.ownerUsername || '').trim().toLowerCase();
  const normalizedUsername = String(memberUser?.username || '').trim().toLowerCase();
  if (!normalizedUsername) return project;

  const members = Array.isArray(project?.members)
    ? project.members.map((member) => String(member || '').trim().toLowerCase()).filter(Boolean)
    : [];
  const memberSet = new Set([ownerUsername, ...members].filter(Boolean));
  memberSet.add(normalizedUsername);

  const existingTeamMembers = Array.isArray(project?.teamMembers) ? project.teamMembers : [];
  const hasTeamMember = existingTeamMembers.some(
    (member) => String(member?.username || member?.name || '').trim().toLowerCase() === normalizedUsername
  );
  const normalizedProfile = normalizeAuthUser(memberUser);
  const nextTeamMembers = hasTeamMember
    ? existingTeamMembers
    : [
        ...existingTeamMembers,
        buildMemberFromUsername(
          normalizedUsername,
          existingTeamMembers.length,
          ownerUsername,
          { username: normalizedUsername, name: normalizedUsername },
          normalizedProfile
        ),
      ];

  return {
    ...project,
    members: Array.from(memberSet),
    teamMembers: nextTeamMembers,
  };
};

const removeProjectMemberRecord = (project, usernameToRemove) => {
  const normalizedUsername = String(usernameToRemove || '').trim().toLowerCase();
  const ownerUsername = String(project?.ownerUsername || '').trim().toLowerCase();
  if (!normalizedUsername || normalizedUsername === ownerUsername) return project;

  const members = Array.isArray(project?.members)
    ? project.members
        .map((member) => String(member || '').trim().toLowerCase())
        .filter((member) => member && member !== normalizedUsername)
    : [];
  const nextMembers = Array.from(new Set([ownerUsername, ...members].filter(Boolean)));

  const nextTeamMembers = Array.isArray(project?.teamMembers)
    ? project.teamMembers.filter(
        (member) => String(member?.username || member?.name || '').trim().toLowerCase() !== normalizedUsername
      )
    : project?.teamMembers;

  return {
    ...project,
    members: nextMembers,
    teamMembers: nextTeamMembers,
  };
};

// --- Main Application Component ---
export default function App() {
  const [currentUser, setCurrentUser] = useState(() => {
    try {
      const data = localStorage.getItem(AUTH_USER_KEY);
      return data ? normalizeAuthUser(JSON.parse(data)) : null;
    } catch {
      return null;
    }
  });

  useEffect(() => {
    ensureLocalTestUsers();
  }, []);

  useEffect(() => {
    if (typeof window === 'undefined' || typeof document === 'undefined') return undefined;

    const rootElement = document.documentElement;
    const syncIpadClass = () => {
      const deviceState = getIpadViewportState();
      rootElement.classList.toggle('pm-ipad', deviceState.isIpad);
      rootElement.classList.toggle('pm-ipad-portrait', deviceState.isIpad && deviceState.isPortrait);
      rootElement.classList.toggle('pm-ipad-landscape', deviceState.isIpad && deviceState.isLandscape);
    };

    syncIpadClass();
    window.addEventListener('resize', syncIpadClass);
    window.addEventListener('orientationchange', syncIpadClass);

    return () => {
      window.removeEventListener('resize', syncIpadClass);
      window.removeEventListener('orientationchange', syncIpadClass);
      rootElement.classList.remove('pm-ipad');
      rootElement.classList.remove('pm-ipad-portrait');
      rootElement.classList.remove('pm-ipad-landscape');
    };
  }, []);

  const handleAuthSuccess = (user) => {
    const safeUser = normalizeAuthUser(user);
    if (safeUser?.id) {
      ACCOUNT_DB_VERSION_BY_USER.delete(safeUser.id);
    }
    setCurrentUser(safeUser);
    localStorage.setItem(AUTH_USER_KEY, JSON.stringify(safeUser));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_USER_KEY);
    ACCOUNT_DB_SAVE_QUEUE_BY_USER.clear();
    ACCOUNT_DB_VERSION_BY_USER.clear();
  };

  const handleCurrentUserUpdate = (user) => {
    const safeUser = normalizeAuthUser({
      ...(currentUser && typeof currentUser === 'object' ? currentUser : {}),
      ...(user && typeof user === 'object' ? user : {}),
      authToken: String(user?.authToken || currentUser?.authToken || '').trim(),
    });
    setCurrentUser(safeUser);
    localStorage.setItem(AUTH_USER_KEY, JSON.stringify(safeUser));
  };

  const pathname = String(typeof window !== 'undefined' ? window.location.pathname : '').trim().toLowerCase();
  const isStandalonePrivacyPath = pathname === '/privacy' || pathname === '/privacy/';
  const shouldForceAuthScreenForLineBridge = (() => {
    const url = getCurrentLocationUrl();
    if (!url) return false;
    return Boolean(getLineLinkTokenFromLocationUrl(url) || getLineBridgeIdFromLocationUrl(url));
  })();

  if (isStandalonePrivacyPath) {
    return <LegalPrivacyTermsPage />;
  }

  return (
    <PopupProvider>
      {!currentUser || shouldForceAuthScreenForLineBridge ? (
        <AuthScreen onAuthSuccess={handleAuthSuccess} />
      ) : (
        <CalendarApp
          currentUser={currentUser}
          onLogout={handleLogout}
          onUpdateCurrentUser={handleCurrentUserUpdate}
        />
      )}
    </PopupProvider>
  );
}

